#include<bits/stdc++.h>
using namespace std;
struct node
{
    int s,q;
    bool operator<(const node&b)const
    {
        return s<b.s;
    }
}a[100010];
int sums[100010],sumd[100010];
int main()
{
    int n,c,f;
    scanf("%d%d%d",&n,&c,&f);
    for(int i=1;i<=c;i++)
    {
        scanf("%d%d",&a[i].s,&a[i].q);
    }
    sort(a+1,a+1+c);
    int sum1=0;
    priority_queue<int> q;
    for(int i=c;i>c-n/2;i--)
    {
        q.push(a[i].q);
        sum1+=a[i].q;
    }
    sumd[c-n/2+1]=sum1;
    for(int i=c-n/2;i>=n/2+1;i--)
    {
        if(a[i].q<q.top())
        {
            sum1-=q.top();
            q.pop();
            q.push(a[i].q);
            sum1+=a[i].q;
        }
        sumd[i]=sum1;
    }
    while(!q.empty())
    {
        q.pop();
    }
    sum1=0;
    for(int i=1;i<=n/2;i++)
    {
        q.push(a[i].q);
        sum1+=a[i].q;
    }
    sums[n/2]=sum1;
    for(int i=n/2+1;i<=c-n/2;i++)
    {
        if(a[i].q<q.top())
        {
            sum1-=q.top();
            q.pop();
            q.push(a[i].q);
            sum1+=a[i].q;
        }
        sums[i]=sum1;
    }
    int temp=n/2;
    for(int i=c-n/2;i>=n/2+1;i--)
    {
        if(sums[i-1]+sumd[i+1]+a[i].q<=f)
        {
            printf("%d",a[i].s);
            return 0;
        }
    }
    printf("-1");
    return 0;
}
